    >
      <Icon size={22} aria-hidden />
      <span style={{ fontSize: 10, color: 'var(--pcs-colors-text-subtle)', textAlign: 'center', lineHeight: 1.3, wordBreak: 'break-word' }}>
        {name.replace(/Icon$/, '')}
      </span>
    </div>
  )
}

